var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"…오늘도 없나?","JPN":"……今日もいないかな？","ENG":"...Is she not home again today?","TWN":"…今天也不在家嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":null,"R":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"루 양을 만나러 온 거니?","JPN":"ルーさんに会いに来たのか？","ENG":"Are you here to see Lugh?","TWN":"你是來找露的嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":null,"R":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"으악, 깜짝아.","JPN":"うわっ、びっくりした。","ENG":"Whoa! You almost scared me to death.","TWN":"啊啊，嚇我一跳。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"할아버지가 왜 여깄어요?","JPN":"なんでおじいちゃんがここにいるんですか？","ENG":"What are you doing here, gramps?","TWN":"奇恩爺爺你怎麼在這裡？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"가게에 주문받은 맞춤옷이 완성돼서 말이다.","JPN":"お店で頼まれた服が完成したからな。","ENG":"I am delivering the finished custom clothes to its owner.","TWN":"店裡訂做的衣服已經完成了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"그런데, 아무래도 집주인이 자릴 비운 모양이구나.","JPN":"ところで、どうやら主が留守中のようだ。","ENG":"But it seems that no one is home at the moment.","TWN":"不過看起來房子的主人不在家呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"나흘째 비어있어요.","JPN":"4日も戻ってきてないんですよ。","ENG":"It's been empty for the last four days.","TWN":"已經空了四天了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"다시 돌아온 줄 알았는데… 착각이었나봐요.","JPN":"今日はいると思ったのに……勘違いだったみたいです。","ENG":"I thought she'd be back by now... but I guess I was wrong.","TWN":"還以為回來了…看來是我搞錯了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"그러고보니, 모르가나 아가씨가 자릴 비운 지도 그쯤 됐지.","JPN":"そういえば、モルガナお嬢様も家を出てそれくらいになるか。","ENG":"Come to think of it, Miss Morgana has also been missing since about that time.","TWN":"說起來，莫甘娜小姐也差不多離開那麼久了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"두 사람은 아마도 중요한 일로 잠시 자릴 비운 걸게다.","JPN":"二人はたぶん、大事な仕事でしばらくいないのだろうよ。","ENG":"I'm sure that both are temporarily absent to do something important.","TWN":"她們二個可能是因為重要的事情暫時離開了吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"그럼… 다행이고요, 뭐.","JPN":"それならいいんですけど……","ENG":"Well, that's reassuring to know.","TWN":"那…那就好。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"어머니 건강은 괜찮아지셨니?","JPN":"母は元気になったか？","ENG":"How is your mother?","TWN":"你的媽媽最近好點了嗎？"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"이제 목발 짚고 밖에 나올 정도는 되세요.","JPN":"はい。もう松葉杖をついて外に出られるようになりました。","ENG":"She's now able to go out of the house using her crutches.","TWN":"現在已經能拄著拐杖出門了。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"하지만, 언젠가 또 마물이 나타날 수 있다고 생각하면… 안심이 안돼요.","JPN":"でも、またいつ魔物が現われるかと思うと……不安でたまりません。","ENG":"But thinking about how the monster could attack the village again... I don't think it's safe for her.","TWN":"但是，我一想到怪物可能隨時會再出現…就無法安心。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"여기에 온 것도 그런 걱정 때문이겠구나.","JPN":"ここにも心配で来たのだな。","ENG":"So you're here out of concern for your mother, correct?","TWN":"所以你才來這裡找她嗎？"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"어쩌면… 마물과 싸우는 법을 배울 수 있지 않을까 해서요.","JPN":"もしかしたら……魔物と戦う方法を教えてもらえるんじゃないかなって。","ENG":"I was wondering... if she could teach me how to fight those monsters.","TWN":"我想…拜託她教我與怪物戰鬥的方法。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"비웃음을 사고 쫓겨날 수도 있겠지만… 그 정도는 각오하고 있어요.","JPN":"笑われて追い返されるかもしれませんが……それは覚悟してます。","ENG":"She might laugh at the idea and kick me out, but... I still think I should ask.","TWN":"就算被嘲笑，被趕走…我也做好了心理準備。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"너도 직접 봤겠지. 루 양이 싸우는 모습을 말이야.","JPN":"お前もその目で見ただろう？　ルーさんが戦っている姿を。","ENG":"You saw how Ms. Lugh fought with your own eyes too.","TWN":"你親眼看到過露戰鬥的樣子吧？"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"동토 너머의 먼나라에서 온 전사라던데, 정말 멋지지 않더냐?","JPN":"凍土の向こうにある遠い国から来た戦士らしいが、勇ましいではないか？","ENG":"She is a warrior from a distant country beyond the gelid lands. Didn't she look so great?","TWN":"露是來自凍土另一邊的戰士，她很強吧？"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"네, 정말 멋지게 마물들을 물리쳤어요.","JPN":"はい、魔物たちをやっつける姿は本当にかっこよかったです。","ENG":"Yeah, she really gave those monsters a beating.","TWN":"很強，三兩下就解決掉怪物…"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"그 사람이 빛난다고 느껴질 만큼.","JPN":"眩しいくらいに輝いていました。","ENG":"I could almost see an aura around her.","TWN":"感覺她就像在發光一樣。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"그 사람에게 빚을 갚고 싶은데… 어떻게 해야할지 모르겠어요.","JPN":"あの人に恩返ししたいのに……どうしたらいいかわからなくて。","ENG":"I want to repay her somehow... but I don't know what to do.","TWN":"我想報答她…但不知道該怎麼做。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"전 마물과 싸우는 법도 모르니까… 앞으로도 성자에게 도움만 받게 되겠죠.","JPN":"僕は魔物と戦う術も知らないし……これからもずっと聖者に助けてもらうしかないのでしょうね。","ENG":"Because I don't know how to fight monsters... and I'll have to rely on Helgons for protection.","TWN":"我連怎麼與怪物戰鬥都不知道…以後也只能依靠聖者的幫助。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"글쎄. 그건 네가 어떤 노력을 하느냐에 달렸지.","JPN":"さあな。それはお前がどんな努力をするかにかかっているさ。","ENG":"Hmm, I think it's up to how much effort you are willing to put into it.","TWN":"這取決於你如何努力。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"전 애초에 성자도 아니잖아요.","JPN":"だって僕はそもそも聖者でもないでしょう？","ENG":"But I'm not even a Helgon.","TWN":"我本來就不是聖者。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KAROLIS_ROOT_NPC_NULL","text":{"KOREA":"그 사람이 마물과 싸우는 걸 보면서, 제가 얼마나 작고 연약한 존재인지 깨달았어요.","JPN":"あの人が魔物と戦う姿を見て、僕がどんなに小さくて弱い存在なのか思い知らされました。","ENG":"Seeing her fight made me realize how small and weak I am.","TWN":"看到那個人與怪物戰鬥，我才意識到自己是多麼地渺小和脆弱。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"KAROLIS_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};